INSERT INTO `knowledge_base` VALUES (1, '发热门诊在哪里？', '发热门诊位于门诊楼1层东侧，24小时开放。', '科室位置', NULL, 2, 1, 0, '2026-06-16 15:55:52', '2026-06-25 12:48:57', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (2, 'CT检查在几楼？', 'CT检查室位于医技楼2层，请先到1层登记窗口办理登记手续。', '检查指引', NULL, 0, 1, 0, '2026-06-16 15:55:52', '2026-06-24 22:40:59', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (3, '明天心内科有专家门诊吗？', '心内科专家门诊每周一、三、五上午8:00-12:00开放，建议提前预约。', '门诊咨询', 1782362925000002, 0, 1, 0, '2026-06-16 15:55:52', '2026-06-25 12:48:45', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (4, '怎么预约挂号？', '您可通过微信公众号、医院APP或官网在线预约挂号，也可拨打客服热线010-12345678。', '挂号指引', NULL, 0, 1, 0, '2026-06-16 15:55:52', '2026-06-16 15:55:52', 'FAQ');
INSERT INTO `knowledge_base` VALUES (5, '医保报销需要什么材料？', '需携带：①社保卡/医保卡 ②身份证 ③门诊/住院病历 ④费用清单 ⑤相关检查报告单。', '医保政策', NULL, 0, 1, 0, '2026-06-16 15:55:52', '2026-06-24 22:40:59', 'INSURANCE');
INSERT INTO `knowledge_base` VALUES (6, '呼吸内科在几楼？', '呼吸内科位于门诊楼3层东侧A区，联系电话010-12345601。门诊时间：周一至周五 8:00-17:00，周六 8:00-12:00。', '科室位置', 1782362925000001, 10, 1, 0, '2026-06-16 18:46:39', '2026-06-25 12:48:45', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (7, '心内科专家有哪些？', '心内科专家包括：张伟主任医师（擅长冠心病、高血压、心律失常），每周一、三、五上午出诊；李红副主任医师（擅长心力衰竭、心肌病），每周二、四上午出诊。', '医生信息', 1782362925000002, 15, 1, 0, '2026-06-16 18:46:39', '2026-06-25 12:48:45', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (8, '做CT检查需要空腹吗？', '腹部CT检查需要空腹4-6小时，其他部位CT一般不需要空腹。CT检查前请到医技楼2层登记窗口办理手续，检查结果可在检查后2小时通过医院APP或自助机查询。', '检查指引', NULL, 8, 1, 0, '2026-06-16 18:46:39', '2026-06-24 22:40:59', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (9, '如何办理住院手续？', '办理住院流程：①医生开具住院通知单 ②携带身份证、医保卡到住院部1层入院登记窗口办理 ③缴纳住院押金（可使用现金、银行卡、微信/支付宝）④凭住院证到相应病区报到。住院部电话：010-12345610。', '就医流程', NULL, 20, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (10, '儿童发热应该挂哪个科？', '儿童（14岁以下）发热请挂儿科。若伴有皮疹、腹泻等症状，儿科医生会视情况建议转诊。儿科位于门诊楼2层西侧，设有专门的儿童候诊区。', '导诊指引', NULL, 12, 1, 0, '2026-06-16 18:46:39', '2026-06-25 12:48:57', 'FAQ');
INSERT INTO `knowledge_base` VALUES (11, '医院停车场怎么收费？', '医院停车场收费标准：前30分钟免费，30分钟至2小时收费5元，2小时后每小时加收2元，24小时最高收费30元。门诊患者凭当日挂号单可享受2小时免费停车。停车场入口位于医院南门。', '其他', NULL, 5, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (12, '医保报销比例是多少？', '医保报销比例因医保类型、药品类别、检查项目不同而异。职工医保门诊报销比例约为50%-70%，住院报销比例约为70%-90%。具体请持社保卡到门诊1层医保办公室咨询，或拨打医保办电话010-12345611。', '医保政策', NULL, 25, 1, 0, '2026-06-16 18:46:39', '2026-06-24 22:40:59', 'INSURANCE');
INSERT INTO `knowledge_base` VALUES (13, '口罩应该戴哪种？', '普通门诊就诊建议佩戴医用外科口罩，发热患者建议佩戴N95或KN95口罩。医院门诊大厅入口处提供免费口罩领取。', '其他', NULL, 3, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (14, '医院有WiFi吗？', '医院提供免费WiFi服务。网络名称：Hospital-WiFi，连接后通过手机号验证即可上网。门诊楼、住院楼、医技楼均已全覆盖。', '其他', NULL, 6, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (15, '怀孕早期感冒了怎么办？', '孕早期感冒请及时到妇产科就诊，切勿自行服药。妇产科位于门诊楼6层，电话010-12345606。如伴有高热（体温超过38.5℃），请立即就医。', '导诊指引', NULL, 10, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (16, '胃镜检查疼不疼？需要准备什么？', '普通胃镜可能会有轻微不适和恶心感。无痛胃镜在麻醉下进行，检查过程无痛感。准备事项：①检查前禁食8小时、禁水4小时 ②携带心电图报告 ③需家属陪同 ④检查后2小时方可进食。胃镜室位于医技楼3层。', '检查指引', NULL, 18, 1, 0, '2026-06-16 18:46:39', '2026-06-24 22:40:59', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (17, '周末可以体检吗？', '体检中心工作时间为周一至周六 7:30-11:30，周六上午可进行常规体检。周日及法定节假日休息。体检预约电话：010-12345608，也可通过医院微信公众号在线预约。', '其他', NULL, 7, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (18, '高血压日常要注意什么？', '高血压患者日常注意事项：①低盐饮食，每日食盐控制在6克以内 ②规律服药，不要自行停药 ③定期测量血压，建议每日早晚各一次 ④适度运动，如散步、太极 ⑤保持情绪稳定，避免激动 ⑥定期复诊，建议每3个月到心内科复查。', '健康宣教', 1782362925000002, 30, 1, 0, '2026-06-16 18:46:39', '2026-06-25 12:48:45', 'FAQ');
INSERT INTO `knowledge_base` VALUES (19, '骨科在几楼？看什么病？', '骨科位于门诊楼2层北侧D区。诊疗范围包括：骨折、关节脱位、颈椎病、腰椎间盘突出、骨关节炎、骨质疏松、运动损伤等。骨科主任赵敏擅长微创关节镜手术。', '科室位置', 1782362925000011, 8, 1, 0, '2026-06-16 18:46:39', '2026-06-25 12:48:57', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (20, '医院的投诉渠道有哪些？', '如对医院服务不满意，可通过以下渠道反馈：①门诊大厅1层患者服务中心 ②拨打投诉电话010-12345609 ③医院官网\"院长信箱\" ④微信公众号\"投诉建议\"入口。我们会在3个工作日内回复处理结果。', '其他', NULL, 2, 1, 0, '2026-06-16 18:46:39', '2026-06-16 18:46:39', 'FAQ');
INSERT INTO `knowledge_base` VALUES (21, '咳嗽呼吸困难胸闷', '咳嗽、呼吸困难、胸闷是呼吸系统常见症状，建议就诊呼吸内科（门诊楼3层东侧A区）。若伴有发热请先到发热门诊筛查。若症状严重（如呼吸困难、胸痛），请立即拨打120。', '导诊指引', 1782362925000001, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-25 12:48:45', 'FAQ');
INSERT INTO `knowledge_base` VALUES (22, '头痛头晕眩晕', '头痛、头晕、眩晕等可能是神经系统问题，建议就诊神经内科（门诊楼5层南侧C区）。如伴有高血压请同时关注心内科。持续性剧烈头痛建议尽快就医。', '导诊指引', 1782362925000003, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-25 12:48:45', 'FAQ');
INSERT INTO `knowledge_base` VALUES (23, '胸痛心悸心慌', '胸痛、心悸、心慌等症状可能涉及心血管问题，建议立即就诊心内科（门诊楼4层西侧B区）。若胸痛剧烈、伴有大汗淋漓，请立即拨打120急救。', '导诊指引', 1782362925000002, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-25 12:48:45', 'FAQ');
INSERT INTO `knowledge_base` VALUES (24, '骨折扭伤关节疼痛腰痛', '骨折、关节扭伤、腰痛、颈椎病等问题属于骨科诊疗范围。骨科位于门诊楼2层北侧D区，主任赵敏擅长微创关节镜手术。', '导诊指引', 1782362925000011, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-25 12:48:57', 'FAQ');
INSERT INTO `knowledge_base` VALUES (25, '发烧发热体温高', '体温超过37.3℃请先到发热门诊（门诊楼1层东侧，24小时开放）进行筛查。14岁以下儿童发热请挂儿科。伴有皮疹、腹泻等症状请告知分诊护士。', '导诊指引', NULL, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-25 12:48:57', 'FAQ');
INSERT INTO `knowledge_base` VALUES (26, '肚子疼腹痛腹泻恶心呕吐', '腹痛、腹泻、恶心、呕吐等症状建议就诊消化内科（门诊楼3层）。若为右下腹剧痛请警惕阑尾炎；儿童腹痛可先就诊儿科。', '导诊指引', NULL, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-16 19:25:37', 'FAQ');
INSERT INTO `knowledge_base` VALUES (27, '皮肤红疹瘙痒过敏', '皮肤红疹、瘙痒、过敏等症状请就诊皮肤科。如伴有发热或呼吸困难可能是严重过敏反应，请立即到急诊。', '导诊指引', NULL, 0, 1, 0, '2026-06-16 19:25:37', '2026-06-16 19:25:37', 'FAQ');
INSERT INTO `knowledge_base` VALUES (30, '挂号需要带什么证件？', '挂号需携带本人身份证或社保卡。首次就诊患者请到门诊大厅1层挂号窗口办理就诊卡。14岁以下儿童请携带户口本或出生证明。', '挂号指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (31, '检查结果多久能出来？', '常规血常规、尿常规约30分钟出结果；生化全套约2小时；CT、X光片约2小时；核磁共振（MRI）约4小时；病理检查约3-5个工作日。结果可通过医院APP、自助机查询或打印。', '检查指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (32, '医院的就诊流程是怎样的？', '就诊流程：挂号(线上或窗口)→到相应科室候诊区报到→医生看诊→缴费(手机/自助机/窗口)→做检查/取药→回诊室给医生看结果。每一步都有导诊标识和志愿者协助。', '就医流程', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (33, '可以代家人挂号吗？', '可以代家人挂号。线上预约需使用患者本人的身份信息注册。现场挂号请携带患者的身份证或社保卡。代取药需携带患者身份证及代办人身份证。', '挂号指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (34, '住院需要准备什么物品？', '住院建议携带：身份证、医保卡、换洗衣物、拖鞋、洗漱用品(毛巾牙刷)、手机充电器、少量现金。医院提供热水瓶、病号服。贵重物品请勿带入病房。', '就医流程', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (35, '医院的就诊时间是怎样的？', '门诊时间：周一至周五 8:00-12:00、14:00-17:30；周六 8:00-12:00；周日及法定节假日休息。急诊科24小时开放。发热门诊24小时开放。', '其他', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (36, '体检需要预约吗？有哪些项目？', '体检需要提前预约，可通过电话010-12345608或微信公众号预约。基础套餐(血尿常规+肝功肾功+血脂血糖+心电图+胸片)288元；全面套餐(基础+彩超+肿瘤标志物)588元；VIP套餐(全面+CT+胃镜)1288元。', '其他', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (37, '怀孕了应该挂哪个科？', '确认怀孕或孕期检查请挂妇产科(门诊楼6层)。如有腹痛、出血等异常情况请立即到妇产科急诊。建档需在孕12周内，携带身份证和B超单到妇产科门诊办理。', '导诊指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (38, '腰疼腿麻挂什么科？', '腰痛伴腿麻可能是腰椎间盘突出或坐骨神经痛，建议挂骨科(门诊楼5层)。如伴有下肢水肿请同时就诊肾内科。长期久坐工作者注意调整坐姿，避免久坐。', '导诊指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (39, '眼睛红肿视力模糊怎么办？', '眼睛红肿、疼痛、视力突然下降请及时就诊眼科(门诊楼7层东侧)。不要自行滴眼药水，以免延误病情。化学物品溅入眼睛请立即用大量清水冲洗后就医。', '导诊指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (40, '耳朵疼听力下降流脓水', '耳朵疼痛、听力下降、流脓水等症状建议就诊耳鼻喉科(门诊楼7层西侧)。切勿用棉签深挖耳道。急性中耳炎需及时治疗，避免转为慢性。', '导诊指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (41, '糖尿病血糖控制不好怎么办？', '血糖控制不佳建议就诊内分泌科(门诊楼4层东侧A区)。医生会评估您的用药方案并提供饮食运动指导。建议就诊前记录近一周的血糖监测数据。', '导诊指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'FAQ');
INSERT INTO `knowledge_base` VALUES (42, '消化内科在几楼？', '消化内科位于门诊楼3层西侧B区，电话010-12345602。胃镜室位于医技楼3层，肠镜室位于医技楼3层。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (43, '儿科在几楼？', '儿科位于门诊楼2层西侧儿童诊区，设有独立的儿童候诊区和游乐区。儿科急诊24小时开放，在急诊科旁设有儿科急诊诊室。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (44, '妇产科怎么走？', '妇产科位于门诊楼6层，进入门诊大厅后乘电梯直达6层。产科门诊在6层东侧，妇科门诊在6层西侧。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (45, '眼科在几楼？', '眼科位于门诊楼7层东侧。配镜中心在1层大厅西侧。白内障日间手术中心在住院楼8层。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (46, '急诊科在哪里？', '急诊科位于门诊楼1层西侧，有独立入口(急诊通道)，24小时开放。急诊设有红区(抢救区)、黄区(留观区)、绿区(普通急诊)。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (47, '皮肤科在几楼？', '皮肤科位于门诊楼2层东侧C区。皮肤科设有独立药房和治疗室。激光美容室在皮肤科内。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (48, '化验室检验科在哪里？', '检验科位于医技楼1层。常规抽血时间为周一至周六 7:30-11:00。空腹抽血项目请在前一天晚上10点后禁食。', '检查指引', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (49, '药房在哪里？', '门诊药房位于门诊大厅1层西侧。中药房在门诊大厅1层东侧。取药时请出示处方和缴费凭证。', '科室位置', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'NAVIGATION');
INSERT INTO `knowledge_base` VALUES (50, '陈强医生怎么样？', '陈强主任医师是呼吸内科专家，从事呼吸内科临床工作30年，中华医学会呼吸病学分会委员。擅长慢性阻塞性肺疾病、支气管哮喘、肺部感染的诊治。出诊时间：周一、周三、周五上午。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (51, '吴敏医生擅长什么？', '吴敏主任医师是儿科主任，从事儿科临床工作28年。擅长儿童呼吸系统疾病、新生儿疾病、儿童保健及生长发育评估。出诊时间：周一至周五全天，周六上午。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (52, '刘洋医生怎么预约？', '刘洋副主任医师是心内科冠脉介入治疗专家，擅长冠脉支架植入术。出诊时间：周二、周四上午。可通过微信公众号、医院APP或电话010-12345678预约。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (53, '有好的骨科医生推荐吗？', '骨科有两位专家：赵敏主任医师擅长微创关节镜手术(膝、肩、髋关节)，从事骨科临床20年。马超主治医师擅长运动损伤和骨折创伤，肩膝关节镜手术经验丰富。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (54, '李明医生看什么病？', '李明主治医师是神经内科医生，擅长头痛、眩晕、脑血管疾病的诊治。出诊时间：周一至周五全天。如您有反复头痛、头晕、睡眠障碍等问题可挂他的号。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (55, '王芳医生简介', '王芳副主任医师是呼吸内科副主任，擅长哮喘、慢阻肺、肺部感染的诊治，对呼吸系统疑难杂症有丰富经验。出诊时间：周二、周四全天，周三下午。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (56, '郑华医生擅长什么手术？', '郑华主任医师是妇产科主任，擅长腹腔镜子宫肌瘤剔除、卵巢囊肿切除、全子宫切除术等微创手术，以及高危妊娠管理和产后出血救治。出诊时间：周一、周三全天。', '医生信息', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DOCTOR');
INSERT INTO `knowledge_base` VALUES (57, '消化内科能看什么病？', '消化内科诊疗范围：胃痛、胃胀、反酸、烧心、恶心呕吐、腹痛腹泻、便秘、便血、黄疸、肝炎、肝硬化、胰腺炎等。配备高清电子胃镜、结肠镜、胶囊内镜等设备。', '科室介绍', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (58, '儿科能看哪些病？', '儿科诊疗范围(14岁以下)：感冒发烧、咳嗽哮喘、呕吐腹泻、皮疹过敏、生长发育迟缓、营养不良、新生儿黄疸等。不开展儿童外科手术(需转小儿外科)。', '科室介绍', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (59, '皮肤科治什么？', '皮肤科诊疗范围：湿疹、荨麻疹、痤疮、银屑病、白癜风、脱发、灰指甲、各种痣和皮肤肿瘤、性传播疾病等。开展激光祛斑、点阵激光、冷冻治疗等。', '科室介绍', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (60, '内分泌科看什么？', '内分泌科诊疗范围：糖尿病及并发症、甲亢/甲减、甲状腺结节、痛风、高尿酸血症、骨质疏松、肥胖症、多囊卵巢综合征、肾上腺疾病等。', '科室介绍', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (61, '急诊科收治什么病人？', '急诊科24小时接诊：急性胸痛、呼吸困难、大出血、严重外伤骨折、急性中毒、高热惊厥、意识障碍、急性腹痛等。分诊护士会根据病情严重程度安排就诊顺序，危重患者优先。', '科室介绍', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (62, '呼吸内科诊疗范围', '呼吸内科诊疗范围：感冒、流感、急慢性支气管炎、肺炎、哮喘、慢阻肺、肺结节、肺癌筛查、胸腔积液、气胸等。开展肺功能检查、支气管镜检查、睡眠呼吸监测。', '科室介绍', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'DEPARTMENT');
INSERT INTO `knowledge_base` VALUES (63, '异地医保怎么报销？', '异地就医需先在国家医保服务平台APP办理异地就医备案。备案成功后持社保卡到我院医保办(门诊1层)登记，出院时可实现异地直接结算。备案前发生的费用需回参保地手工报销。', '医保政策', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'INSURANCE');
INSERT INTO `knowledge_base` VALUES (64, '自费项目有哪些？', '以下项目通常需自费：美容整形、牙齿矫正/种植、近视激光手术、非治疗性体检套餐、部分进口药品和耗材、VIP病房差价等。具体请就诊时咨询医生或医保办公室。', '医保政策', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'INSURANCE');
INSERT INTO `knowledge_base` VALUES (65, '门诊报销和住院报销有什么区别？', '门诊报销通常有年度起付线(如1800元)，超过部分按比例报销(50%-70%)，有年度封顶线。住院报销起付线较低(如1300元)，报销比例较高(70%-90%)，封顶线较高。具体政策因地区和医保类型不同而异。', '医保政策', NULL, 0, 1, 0, '2026-06-25 12:20:26', '2026-06-25 12:20:26', 'INSURANCE');
